for (const s of scenarios) {
  s.level = 2;
  s.tag = 'advanced';
  const seen = new Set();
  for (const word of s.words) {
    if (seen.has(word.w)) throw new Error(`Duplicate word "${word.w}" in scenario ${s.id}`);
    seen.add(word.w);
  }
  if (s.words.length !== 80) throw new Error(`Scenario ${s.id} has ${s.words.length} words, expected 80`);
}

function fmtWord(o) {
  return `{ w: '${o.w.replace(/'/g, "\\'")}', pos: '${o.pos}', zh: '${o.zh.replace(/'/g, "\\'")}', syn: '${o.syn.replace(/'/g, "\\'")}', ex: '${o.ex.replace(/'/g, "\\'")}', exZh: '${o.exZh.replace(/'/g, "\\'")}', level: 2, tag: 'advanced' }`;
}

const lines = [
  '/* TOEIC vocab Level 2 — gold certificate (860+) advanced themes */',
  'window.WA_TOEIC_VOCAB_L2 = {',
  "  level: 2,",
  "  tag: 'advanced',",
  "  label: 'Level 2｜金色證書特攻（860+）',",
  '  scenarios: [',
];

for (let si = 0; si < scenarios.length; si++) {
  const s = scenarios[si];
  lines.push('    {');
  lines.push(`      id: '${s.id}',`);
  lines.push(`      name: '${s.name}',`);
  lines.push(`      nameEn: '${s.nameEn}',`);
  lines.push(`      tip: '${s.tip}',`);
  lines.push('      level: 2,');
  lines.push("      tag: 'advanced',");
  lines.push('      words: [');
  for (let wi = 0; wi < s.words.length; wi++) {
    const comma = wi < s.words.length - 1 ? ',' : '';
    lines.push('      ' + fmtWord(s.words[wi]) + comma);
  }
  lines.push('      ]');
  lines.push('    }' + (si < scenarios.length - 1 ? ',' : ''));
}

lines.push('  ]');
lines.push('};');
lines.push('');

const outPath = path.join(__dirname, '..', 'assets', 'js', 'toeic-vocab-l2-data.js');
fs.writeFileSync(outPath, lines.join('\n'), 'utf8');

const counts = scenarios.map((s) => `${s.id}: ${s.words.length}`);
console.log('Word counts per scenario:');
counts.forEach((c) => console.log('  ' + c));
console.log('Total:', scenarios.reduce((n, s) => n + s.words.length, 0));

